     /* Control policy with hysteresis:
      * - Turn pump ON when level < 30 (low threshold)
      * - Turn pump OFF when level > 80 (high threshold)
      * - Hold previous state while 30 <= level <= 80
      */
     if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
         /* Low level: turn pump ON */
         controller->pump_on = true;
         controller->state = CONTROLLER_STATE_PUMPING;
     } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
         /* High level: turn pump OFF */
         controller->pump_on = false;
         controller->state = CONTROLLER_STATE_SAFE_OFF;
     } else {
         /* Mid-band: hold previous state */
         /* If we were pumping and now in mid-band, transition to HOLDING */
         if (controller->pump_on) {
             controller->state = CONTROLLER_STATE_HOLDING;
         } else {
             controller->state = CONTROLLER_STATE_SAFE_OFF;
         }
     }
     break;

 case CONTROLLER_INPUT_SENSOR_TIMEOUT:
 case CONTROLLER_INPUT_INVALID_LEVEL:
     /* Malformed input or timeout: fail safe to PUMP OFF */
     controller->has_valid_sensor = false;
     controller_set_safe_off(controller);
     output.timed_out = (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT);
     break;

 case CONTROLLER_INPUT_NONE:
 default:
     /* No new input: check for timeout based on elapsed time */
     if (controller->has_valid_sensor && input.now_ms > 0) {
         uint32_t elapsed = input.now_ms - controller->last_valid_sensor_ms;
         if (elapsed >= CONTROLLER_SENSOR_TIMEOUT_MS) {
             /* Timeout: fail safe to PUMP OFF */
             controller_set_safe_off(controller);
             output.timed_out = true;
         } else {
             /* Within timeout window: hold previous state */
             if (controller->pump_on) {
                 controller->state = CONTROLLER_STATE_HOLDING;
             } else {
                 controller->state = CONTROLLER_STATE_SAFE_OFF;
             }
         }
     } else {
         /* No valid sensor yet: stay safe off */
         controller_set_safe_off(controller);
     }
     break;
